package auth

import (
	"crypto/subtle"
	"encoding/hex"
)

// compareHashes securely compares two hex-encoded hash strings using constant-time comparison
func compareHashes(stored, input string) bool {
	if len(stored) != len(input) {
		return false
	}

	storedBytes, err := hex.DecodeString(stored)
	if err != nil {
		return false
	}

	inputBytes, err := hex.DecodeString(input)
	if err != nil {
		return false
	}

	return subtle.ConstantTimeCompare(storedBytes, inputBytes) == 1
